const raw = $input.first().json;
const decoded = Buffer.from(raw.content, 'base64').toString('utf-8');
const data = JSON.parse(decoded);
const existingTitles = data.posts.map(p => p.title);
const postCount = data.posts.length;
const categories = ['ratgeber', 'lokal', 'saisonal', 'news'];
const nextCategory = categories[postCount % categories.length];
const currentMonth = new Date().toLocaleString('de-DE', { month: 'long' });
const today = new Date().toISOString().split('T')[0];
return [{ json: { data, existingTitles, nextCategory, currentMonth, today, sha: raw.sha } }];

const openaiResponse = $input.first().json;
const text = openaiResponse.choices[0].message.content.trim();
const newPost = JSON.parse(text);
const imagePrompt = `Professional automotive photography for a German auto glass service blog. Scene: ${newPost.imageAlt}. Photorealistic, commercial quality, bright professional lighting, no text overlays, no people, modern vehicle with glass focus, clean background.`;
return [{ json: { newPost, imagePrompt } }];

const { newPost } = $('Parse ChatGPT Post').first().json;
newPost.image = `/public/images/blog/${newPost.id}.png`;
const { data, sha } = $('Parse blog.json').first().json;
data.posts.unshift(newPost);
const MAX_POSTS = 52;
if (data.posts.length > MAX_POSTS) data.posts = data.posts.slice(0, MAX_POSTS);
const updatedContent = Buffer.from(JSON.stringify(data, null, 2)).toString('base64');
return [{ json: { updatedContent, sha, newPostId: newPost.id, newPostDate: newPost.date } }];

const sitemapRaw = $input.first().json;
const sitemapXml = Buffer.from(sitemapRaw.content, 'base64').toString('utf-8');
const { newPostId, newPostDate } = $('Merge: blog.json aufbauen').first().json;
const newEntry = `  <url>\n    <loc>https://schwarz-autoglas.de/blog.html#${newPostId}</loc>\n    <lastmod>${newPostDate}</lastmod>\n    <changefreq>weekly</changefreq>\n    <priority>0.7</priority>\n  </url>`;
const updated = sitemapXml.replace('</urlset>', newEntry + '\n</urlset>');
const updatedContent = Buffer.from(updated).toString('base64');
return [{ json: { updatedContent, sha: sitemapRaw.sha } }];
